### `AuthGuard.tsx`
```typescript
'use client';

import { useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { useAuth } from '@/hooks/useAuth';

interface AuthGuardProps {
  children: React.ReactNode;
  redirectTo?: string;
  requiredRoles?: string[];
}

export function AuthGuard({
  children,
  redirectTo = '/login',
  requiredRoles = [],
}: AuthGuardProps) {
  const { isAuthenticated, isLoading, user } = useAuth();
  const router = useRouter();

  useEffect(() => {
    if (isLoading) return; // Don't redirect during the rehydration window

    if (!isAuthenticated) {
      router.replace(redirectTo);
      return;
    }

    if (requiredRoles.length > 0 && user) {
      const hasRequiredRole = requiredRoles.some((role) =>
        user.roles.includes(role)
      );
      if (!hasRequiredRole) {
        router.replace('/unauthorized');
      }
    }
  }, [isAuthenticated, isLoading, user, router, redirectTo, requiredRoles]);

  // Render nothing during the hydration window or during redirect
  if (isLoading || !isAuthenticated) {
    return null; // Or return a <LoadingSpinner /> component
  }

  // Role check in render path (defense in depth)
  if (requiredRoles.length > 0 && user) {
    const hasRole = requiredRoles.some((role) => user.roles.includes(role));
    if (!hasRole) return null;
  }

  return <>{children}</>;
}
